    outcome: implementationOutcomeSchema,
    story: z.object({
      id: z.string().min(1),
      title: z.string().min(1),
    }),
    planSummary: z.string().min(1),
    changedFiles: z.array(
      z.object({
        path: z.string().min(1),
        reason: z.string().min(1),
      })
    ),
    tests: z.object({
      added: z.array(z.string().min(1)),
      modified: z.array(z.string().min(1)),
