async function createQuickFixSpecPack(scope: string): Promise<string> {
  const specPackRoot = await createSpecPack(scope, {
    companionMode: "four-file",
  });
  await writeTextFile(
    join(specPackRoot, "package.json"),
    `${JSON.stringify(
      {
        name: "fixture-spec-pack",
