398	export async function readJsonLines<T>(path: string): Promise<T[]> {
399	  const content = await Bun.file(path).text();
400	  return content
401	    .split("\n")
402	    .map((line) => line.trim())
403	    .filter(Boolean)
404	    .map((line) => JSON.parse(line) as T);
405	}
